WITH UPSERT AS (
    UPDATE NIA.TB_PING_ALARM_CNT
       SET ${colunm} = #{alarmCnt}
     WHERE URL = #{url}
     RETURNING *
)
INSERT INTO NIA.TB_PING_ALARM_CNT
(
    URL, ${colunm}
)
SELECT #{url}, #{alarmCnt}
 WHERE NOT EXISTS (SELECT * FROM UPSERT)

